import { forwardRef, type ReactNode } from 'react';
import { cn } from '../../utils/cn';
import styles from './Divider.module.css';

export interface DividerProps {
  orientation?: 'horizontal' | 'vertical';
  label?: ReactNode;
  className?: string;
  'data-testid'?: string;
}

export const Divider = forwardRef<HTMLDivElement, DividerProps>(
  function Divider(
    {
      orientation = 'horizontal',
      label,
      className,
      'data-testid': dataTestId = 'tatva-divider',
    },
    ref,
  ) {
    if (label && orientation === 'horizontal') {
      return (
        <div
          ref={ref}
          role="separator"
          aria-orientation="horizontal"
          className={cn(styles.labeled, className)}
          data-testid={dataTestId}
        >
          <span className={styles.line} />
          <span className={styles.label}>{label}</span>
          <span className={styles.line} />
        </div>
      );
    }
    return (
      <div
        ref={ref}
        role="separator"
        aria-orientation={orientation}
        className={cn(
          orientation === 'vertical' ? styles.vertical : styles.horizontal,
          className,
        )}
        data-testid={dataTestId}
      />
    );
  },
);

.horizontal {
  width: 100%;
  height: 1px;
  background-color: var(--tatva-color-border);
  border: none;
}

.vertical {
  width: 1px;
  align-self: stretch;
  background-color: var(--tatva-color-border);
  border: none;
}

.labeled {
  display: flex;
  align-items: center;
  gap: var(--tatva-space-3);
  color: var(--tatva-color-fg-muted);
  font-family: var(--tatva-font-family);
  font-size: var(--tatva-font-size-xs);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.line {
  flex: 1;
  height: 1px;
  background-color: var(--tatva-color-border);
}

.label {
  flex-shrink: 0;
}
